func (f *CommandFactory) newAgentCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "agent",
		Short: "Invoke AI agents with harness dispatch, quorum, and session logging",
		Long: `Unified interface for dispatching work to AI coding agents.

Supports multiple harnesses (codex, claude, gemini, etc.) with output capture,
token tracking, session logging, and multi-agent quorum.

The embedded DDx agent harness is named 'agent' and is always available without
installing external binaries. Use --harness agent or --profile cheap to route to it.

Profile routing (--profile default|cheap|fast|smart) selects the best available harness
and model automatically. Workflow tools should prefer --profile over --harness to
stay decoupled from harness installation details.

Examples:
  ddx agent run --profile default --prompt task.md
  ddx agent run --profile cheap --prompt task.md
  ddx agent run --profile smart --prompt task.md
  ddx agent run --profile smart --model gpt-5.4   # explicit override; avoid by default
  ddx agent run --harness agent --prompt task.md
  ddx agent run --harness codex --prompt task.md
  ddx agent run --quorum majority --harnesses codex,claude --prompt task.md
  ddx agent list
  ddx agent capabilities agent
  ddx agent capabilities codex
  ddx agent doctor
  ddx agent log`,
		PersistentPreRunE: func(cmd *cobra.Command, args []string) error {
			serverreg.TryRegisterAsync(f.WorkingDir)
			return nil
		},
		Run: func(cmd *cobra.Command, args []string) {
			_ = cmd.Help()
		},
	}

	cmd.AddCommand(f.newAgentRunCommand())
	cmd.AddCommand(f.newAgentCondenseCommand())
	cmd.AddCommand(f.newAgentListCommand())
	cmd.AddCommand(f.newAgentCapabilitiesCommand())
	cmd.AddCommand(f.newAgentDoctorCommand())
	cmd.AddCommand(f.newAgentLogCommand())
	cmd.AddCommand(f.newAgentBenchmarkCommand())
	cmd.AddCommand(f.newAgentUsageCommand())
	cmd.AddCommand(f.newAgentReplayCommand())
	cmd.AddCommand(f.newAgentExecuteBeadCommand())
	cmd.AddCommand(f.newAgentExecuteLoopCommand())
	cmd.AddCommand(f.newAgentExecutionsCommand())
	cmd.AddCommand(f.newAgentWorkersCommand())
	cmd.AddCommand(f.newAgentCatalogCommand())
	cmd.AddCommand(f.newAgentProvidersCommand())
	cmd.AddCommand(f.newAgentModelsCommand())
	cmd.AddCommand(f.newAgentCheckCommand())
	cmd.AddCommand(f.newAgentRouteStatusCommand())
	cmd.AddCommand(f.newAgentMetricsCommand())

	return cmd
}

func (f *CommandFactory) newAgentRunCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:          "run",
		Short:        "Invoke an agent with a prompt",
		SilenceUsage: true,
		RunE: func(cmd *cobra.Command, args []string) error {
			promptFile, _ := cmd.Flags().GetString("prompt")
			promptText, _ := cmd.Flags().GetString("text")
			harness, _ := cmd.Flags().GetString("harness")
			model, _ := cmd.Flags().GetString("model")
			profile, _ := cmd.Flags().GetString("profile")
			effort, _ := cmd.Flags().GetString("effort")
			timeoutStr, _ := cmd.Flags().GetString("timeout")
			quorum, _ := cmd.Flags().GetString("quorum")
			harnesses, _ := cmd.Flags().GetString("harnesses")
			asJSON, _ := cmd.Flags().GetBool("json")
			outputFmt, _ := cmd.Flags().GetString("output")
			worktreeName, _ := cmd.Flags().GetString("worktree")
			permissions, _ := cmd.Flags().GetString("permissions")
			compare, _ := cmd.Flags().GetBool("compare")
			sandbox, _ := cmd.Flags().GetBool("sandbox")
			keepSandbox, _ := cmd.Flags().GetBool("keep-sandbox")
			postRun, _ := cmd.Flags().GetString("post-run")
			arms, _ := cmd.Flags().GetStringArray("arm")

			var timeout time.Duration
			if timeoutStr != "" {
				var err error
				timeout, err = time.ParseDuration(timeoutStr)
				if err != nil {
					return fmt.Errorf("invalid timeout: %w", err)
				}
			}

			// Resolve project root (--project flag > DDX_PROJECT_ROOT > CWD git root)
			projectFlag, _ := cmd.Flags().GetString("project")
			workDir := resolveProjectRoot(projectFlag, f.WorkingDir)
			if worktreeName != "" {
				wtPath, err := resolveWorktree(workDir, worktreeName)
				if err != nil {
					return fmt.Errorf("worktree: %w", err)
				}
				workDir = wtPath
			}

			// Read prompt from stdin if neither file nor text provided
			prompt := promptText
			promptSource := "inline"
			if prompt == "" && promptFile == "" {
				// Check if stdin has data
				stat, _ := os.Stdin.Stat()
				if (stat.Mode() & os.ModeCharDevice) == 0 {
					data, err := io.ReadAll(os.Stdin)
					if err != nil {
						return fmt.Errorf("reading stdin: %w", err)
					}
					prompt = string(data)
					promptSource = "stdin"
				}
			} else if promptFile != "" {
				promptSource = promptFile
			}

			// Comparison mode
			if compare {
				var harnessNames []string
				armModels := map[int]string{}
				armLabels := map[int]string{}

				// Parse --arm flags: "harness:model:label" or "harness:model" or "harness"
				if len(arms) > 0 {
					for i, arm := range arms {
						parts := strings.SplitN(arm, ":", 3)
						harnessNames = append(harnessNames, parts[0])
						if len(parts) >= 2 && parts[1] != "" {
							armModels[i] = parts[1]
						}
						if len(parts) >= 3 {
							armLabels[i] = parts[2]
						} else if len(parts) >= 2 && parts[1] != "" {
							armLabels[i] = parts[0] + "/" + parts[1]
						}
					}
				} else if harnesses != "" {
					harnessNames = strings.Split(harnesses, ",")
				} else {
					return fmt.Errorf("--arm or --harnesses required for --compare mode")
				}

				overrides := config.CLIOverrides{
					Model:       model,
					Effort:      effort,
					Permissions: permissions,
				}
				if timeout > 0 {
					overrides.Timeout = &timeout
				}
				rcfg, _ := config.LoadAndResolve(f.WorkingDir, overrides)
				runtime := agent.CompareRuntime{
					AgentRunRuntime: agent.AgentRunRuntime{
						Prompt:       prompt,
						PromptFile:   promptFile,
						PromptSource: promptSource,
						WorkDir:      workDir,
					},
					Harnesses:   harnessNames,
					ArmModels:   armModels,
					ArmLabels:   armLabels,
					Sandbox:     sandbox,
					KeepSandbox: keepSandbox,
					PostRun:     postRun,
				}
				record, err := agent.RunCompareWithConfigViaService(cmd.Context(), f.WorkingDir, rcfg, runtime)
				if err != nil {
					return err
				}
				if asJSON {
					enc := json.NewEncoder(cmd.OutOrStdout())
					enc.SetIndent("", "  ")
					return enc.Encode(record)
				}
				fmt.Fprintf(cmd.OutOrStdout(), "Comparison %s (%d arms)\n", record.ID, len(record.Arms))
				for _, arm := range record.Arms {
					status := "OK"
					if arm.ExitCode != 0 {
						status = fmt.Sprintf("FAIL (rc=%d)", arm.ExitCode)
					}
					cost := ""
					if arm.CostUSD > 0 {
						cost = fmt.Sprintf(" cost=$%.4f", arm.CostUSD)
					}
					fmt.Fprintf(cmd.OutOrStdout(), "  %-12s %s  tokens=%d  duration=%dms%s\n",
						arm.Harness, status, arm.Tokens, arm.DurationMS, cost)
					if arm.Diff != "" {
						lines := strings.Count(arm.Diff, "\n")
						fmt.Fprintf(cmd.OutOrStdout(), "             diff: %d lines\n", lines)
					}
				}
				return nil
			}

			// Quorum mode
			if quorum != "" || harnesses != "" {
				harnessNames := strings.Split(harnesses, ",")
				if len(harnessNames) == 0 || (len(harnessNames) == 1 && harnessNames[0] == "") {
					return fmt.Errorf("--harnesses required for quorum mode")
				}
				overrides := config.CLIOverrides{
					Model:       model,

--- providers tests ---
package server

import (
	"context"
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"strings"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	agentlib "github.com/DocumentDrivenDX/fizeau"
	"github.com/stretchr/testify/require"
)

// TestListProviders verifies GET /api/providers returns a JSON array containing
// all known harnesses.
func TestListProviders(t *testing.T) {
	dir := setupTestDir(t)
	srv := New(":0", dir)

	req := httptest.NewRequest(http.MethodGet, "/api/providers", nil)
	req.RemoteAddr = "127.0.0.1:12345"
	w := httptest.NewRecorder()
	srv.Handler().ServeHTTP(w, req)

	if w.Code != http.StatusOK {
		t.Fatalf("expected 200, got %d", w.Code)
	}

	var items []ProviderSummary
	if err := json.NewDecoder(w.Body).Decode(&items); err != nil {
		t.Fatalf("decode: %v", err)
	}
	if len(items) == 0 {
		t.Fatal("expected non-empty provider list")
	}

	// Verify required fields are present and not fabricated as "ok"/"0" when unknown.
	svc, err := agent.NewServiceFromWorkDir(dir)
	if err != nil {
		t.Fatalf("NewServiceFromWorkDir: %v", err)
	}
	infos, err := svc.ListHarnesses(context.Background())
	if err != nil {
		t.Fatalf("ListHarnesses: %v", err)
	}
	harnessNames := map[string]bool{}
	for _, info := range infos {
		harnessNames[info.Name] = true
	}

	for _, item := range items {
		if item.Harness == "" {
			t.Error("provider summary missing harness field")
		}
		if !harnessNames[item.Harness] {
			t.Errorf("unexpected harness in response: %q", item.Harness)
		}
		if item.DisplayName == "" {
			t.Errorf("harness %q missing display_name", item.Harness)
		}
		// Status must be one of the defined values.
		switch item.Status {
		case "available", "unavailable", "unknown":
		default:
			t.Errorf("harness %q has invalid status %q", item.Harness, item.Status)
		}
		// AuthState must be one of the defined values.
		switch item.AuthState {
		case "authenticated", "unauthenticated", "unknown":
		default:
			t.Errorf("harness %q has invalid auth_state %q", item.Harness, item.AuthState)
		}
		// QuotaHeadroom must be one of the defined values.
		switch item.QuotaHeadroom {
		case "ok", "blocked", "unknown":
		default:
			t.Errorf("harness %q has invalid quota_headroom %q", item.Harness, item.QuotaHeadroom)
		}
		// SignalSources must contain at least "none" when no signals available.
		if len(item.SignalSources) == 0 {
			t.Errorf("harness %q has empty signal_sources (should be at least [none])", item.Harness)
		}
		// CostClass must not be empty.
		if item.CostClass == "" {
			t.Errorf("harness %q missing cost_class", item.Harness)
		}
		// LastCheckedTS must be present.
		if item.LastCheckedTS == "" {
			t.Errorf("harness %q missing last_checked_ts", item.Harness)
		}
	}

	// All harnesses in the registry must appear in the response.
	found := map[string]bool{}
	for _, item := range items {
		found[item.Harness] = true
	}
	for name := range harnessNames {
		if !found[name] {
			t.Errorf("harness %q missing from provider list response", name)
		}
	}
}

// TestShowProvider verifies GET /api/providers/{harness} returns a full detail
// object for a known harness.
func TestShowProvider(t *testing.T) {
	dir := setupTestDir(t)
	srv := New(":0", dir)

	req := httptest.NewRequest(http.MethodGet, "/api/providers/claude", nil)
	req.RemoteAddr = "127.0.0.1:12345"
	w := httptest.NewRecorder()
	srv.Handler().ServeHTTP(w, req)

	if w.Code != http.StatusOK {
		t.Fatalf("expected 200, got %d: %s", w.Code, w.Body.String())
	}

	var detail ProviderDetail
	if err := json.NewDecoder(w.Body).Decode(&detail); err != nil {
		t.Fatalf("decode: %v", err)
	}

	if detail.Harness != "claude" {
		t.Errorf("expected harness=claude, got %q", detail.Harness)
	}
	if detail.DisplayName == "" {
		t.Error("missing display_name")
	}
	// Status must be one of the defined values.
	switch detail.Status {
	case "available", "unavailable", "unknown":
	default:
		t.Errorf("invalid status %q", detail.Status)
	}
	// AuthState — in test env with no live quota signal, should be "unknown".
	switch detail.AuthState {
	case "authenticated", "unauthenticated", "unknown":
	default:
		t.Errorf("invalid auth_state %q", detail.AuthState)
	}
	// Models array must be present (may be empty).
	if detail.Models == nil {
		t.Error("models field must not be nil (should be empty array when no models)")
	}
	// SignalSources must contain at least one entry.
	if len(detail.SignalSources) == 0 {
		t.Error("signal_sources must not be empty")
	}
	// RoutingSignals.Performance must carry -1 sentinels when no samples.
	perf := detail.RoutingSignals.Performance
	if perf.SampleCount == 0 {
		if perf.SuccessRate != -1 {
			t.Errorf("success_rate should be -1 when sample_count=0, got %v", perf.SuccessRate)
		}
		if perf.P50LatencyMS != -1 {
			t.Errorf("p50_latency_ms should be -1 when sample_count=0, got %v", perf.P50LatencyMS)
		}
		if perf.P95LatencyMS != -1 {
			t.Errorf("p95_latency_ms should be -1 when sample_count=0, got %v", perf.P95LatencyMS)
		}
	}
	// Window must be "7d".
	if perf.Window != "7d" {
		t.Errorf("performance.window should be 7d, got %q", perf.Window)
	}
}

